// linkTrunkTitle is the Trunk badge tooltip: the probe's seen-VID detail when available,
// else the generic message (e.g. ACTIVE, where the box's own VLAN sub-interfaces drove it).
func linkTrunkTitle(iface, detail string) string {
	if detail != "" {
		return iface + " - " + detail
	}
	return iface + " carrying tagged VLAN traffic"
}

